<section x-data="{open: @js($errors->has('password'))}" class="mt-10 border-t border-red-100 pt-8"><h3 class="text-lg font-bold text-red-700">Delete account</h3><p class="mt-1 text-sm text-slate-600">Permanently delete your account and its resources.</p><x-ui.button variant="danger" class="mt-4" @click="open=true">Delete account</x-ui.button><div x-cloak x-show="open" class="fixed inset-0 z-50 grid place-items-center bg-slate-950/70 p-4"><div @click.outside="open=false" class="w-full max-w-lg rounded-3xl bg-white p-6 shadow-2xl dark:bg-slate-900"><form wire:submit="deleteUser" class="grid gap-5"><div><h3 class="text-xl font-bold">Are you sure you want to delete your account?</h3><p class="mt-2 text-sm text-slate-600 dark:text-slate-300">This action cannot be undone. Enter your password to confirm.</p></div><x-ui.input wire:model="password" label="Password" type="password"/><div class="flex justify-end gap-2"><x-ui.button variant="secondary" @click="open=false">Cancel</x-ui.button><x-ui.button variant="danger" type="submit">Delete account</x-ui.button></div></form></div></div></section>
